import datetime as dt
from base64 import urlsafe_b64encode, urlsafe_b64decode
from os import urandom

def generate_token(user_id):
    timestamp = dt.datetime.utcnow()
    payload = {"userId": user_id}

    header = {
        'alg': "HS256",
        'typ': "JWT"
    }
    
    encodedHeader = urlsafe_b64encode(bytes(str(header), encoding="ascii")).decode("ascii")
    encodedPayload = urlsafe_b64encode(bytes(str(payload), encoding="ascii")).decode("ascii")

    return "-----BEGIN JOSE PLAIN HEADER-----\n"+encodedHeader+"\n-----END JOSE PLAIN HEADER-----\n\n" \
        + "-----BEGIN JOSE PLAIN PAYLOAD-----\n"+ encodedPayload +"\n-----END JOSE PLAIN PAYLOAD-----\n\n" \
            + "-----BEGIN HMAC SECRET-----\n"+ urlsafe_b64encode(urandom(10)).decode("ascii")+"\n-----END HMAC SECRET-----"